if r1 is Some && r2 is Some {
        let v1 = r1->Some_0;
        let v2 = r2->Some_0;
        if abstractify_end_points(v1) == abstractify_end_points(v2) {
            assert(abstractify_end_points(v1).len() == v1@.len());
            assert(abstractify_end_points(v2).len() == v2@.len());
            assert(v1@.len() == v2@.len());
            assert forall |i: int| 0 <= i < v1@.len() implies v1@[i] == v2@[i] by {
                assert(abstractify_end_points(v1)[i] == v1@[i]@);
                assert(abstractify_end_points(v2)[i] == v2@[i]@);
                assert(v1@[i]@ == v2@[i]@);
                assert(v1@[i].id@ == v2@[i].id@);
            }
            assert(v1@ =~= v2@);
            assert(v1 == v2);
        }
    }
